import{_ as e,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F01: 營收因子與定價權分析 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260511/F01_營收因子與定價權分析.md","filePath":"審計報告庫/財務審計/6261_久元/20260511/F01_營收因子與定價權分析.md"}'),l={name:"審計報告庫/財務審計/6261_久元/20260511/F01_營收因子與定價權分析.md"};function o(n,a,s,h,u,d){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="f01-營收因子與定價權分析-財務審計專家報告" tabindex="-1">F01: 營收因子與定價權分析 - 財務審計專家報告 <a class="header-anchor" href="#f01-營收因子與定價權分析-財務審計專家報告" aria-label="Permalink to &quot;F01: 營收因子與定價權分析 - 財務審計專家報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？</p></blockquote><h2 id="🎯-專家直斷-74-字" tabindex="-1">🎯 專家直斷（74 字） <a class="header-anchor" href="#🎯-專家直斷-74-字" aria-label="Permalink to &quot;🎯 專家直斷（74 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2024 年營收成長 +17.8%，成長來自自有產品擴張（設備銷售 +11.39%）帶動毛利率。惟營益率連 3 年下滑 15.0%→11.4%，費用膨脹壓縮成長紅利。</li></ul><h2 id="📊-診斷評級-138-字" tabindex="-1">📊 診斷評級（138 字） <a class="header-anchor" href="#📊-診斷評級-138-字" aria-label="Permalink to &quot;📊 診斷評級（138 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：營收 35.2 億（2023）→ 41.5 億（2024，+17.8%）→ 41.1 億（2025，-0.9%）；毛利率 28.3%→30.1%→29.9%；營益率 15.0%→11.6%→11.4%。</li><li><strong>診斷見解</strong>：2024 年營收成長伴隨毛利率提升，屬於產品組合優化型（自有設備佔比 37%→38.6%），具備一定定價權。但營益率持續下滑揭示費用增速失控——2025 年營收僅減 0.9%，營益率卻再跌至 11.4%，費用僵固性壓力明顯。2026 前 5 月營收年比約 -15%，動能續弱。</li></ul><h2 id="🔍-答詢詳解-387-字" tabindex="-1">🔍 答詢詳解（387 字） <a class="header-anchor" href="#🔍-答詢詳解-387-字" aria-label="Permalink to &quot;🔍 答詢詳解（387 字）&quot;">​</a></h2><h3 id="一、驅動因子權重-driver-weight" tabindex="-1">一、驅動因子權重（Driver Weight） <a class="header-anchor" href="#一、驅動因子權重-driver-weight" aria-label="Permalink to &quot;一、驅動因子權重（Driver Weight）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年營收增 6.24 億（+17.8%），毛利率由 28.3% 升至 30.1%（+1.8pp），屬含金量高的混合型成長。對比年報部門資料，代工事業營收+4.27%、自有產品+11.39%，自有產品增速約為代工的 2.7 倍。由於自有產品毛利率顯著高於代工（自有產品部門營利率 50.5% vs 代工 16.0%），2024 年主要成長來自產品組合優化（Price/Mix Up），而非單純衝量。</li><li><strong>深度見解</strong>：2025 年營收微減 0.9%，但自有產品佔比續升至 40.3%，顯示管理層刻意導向高毛利設備業務，透過組合優化支撐毛利率平穩（30.1%→29.9%）。這反映久元具備一定<strong>產品組合調整能力</strong>，能於營收停滯時維持毛利水位。</li></ul><h3 id="二、獲利品質連動-margin-linkage" tabindex="-1">二、獲利品質連動（Margin Linkage） <a class="header-anchor" href="#二、獲利品質連動-margin-linkage" aria-label="Permalink to &quot;二、獲利品質連動（Margin Linkage）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：營益率的連年下滑（15.0%→11.6%→11.4%）是最大警訊。2024 年營收成長 17.8%，但營益率反降 3.4pp，代表營業費用增速（+30.3%）遠超營收增速。費用膨脹吃掉毛利改善的全部紅利還倒虧。</li><li><strong>深度見解</strong>：費用結構中，推銷費用與管理費用增幅顯著，推測與自有設備業務擴張所需之銷售團隊/技術服務人力擴編有關。若營收動能續弱（2026 年趨勢向下），固定費用將進一步壓縮營益率。</li></ul><h3 id="三、未來路徑預測-future-path" tabindex="-1">三、未來路徑預測（Future Path） <a class="header-anchor" href="#三、未來路徑預測-future-path" aria-label="Permalink to &quot;三、未來路徑預測（Future Path）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2026 前 5 月月營收累計約 18.1 億，年比約 -15%，主要因 2025 高基期（12 月單月 4.48 億為當年最高）。2026 Q1 各月營收波動大（1 月 4.13 億→3 月 2.85 億→4 月 3.85 億），尚無穩定回升訊號。</li><li><strong>深度見解</strong>：2025 年自有產品營收 16.9 億已達近年高點，半導體設備需求回溫能否持續將決定 2026 年走向。若設備訂單降溫，營收將退回代工業務 24-25 億的基本盤，營益率恐跌破 10%。</li></ul><h2 id="💡-專家評析-283-字" tabindex="-1">💡 專家評析（283 字） <a class="header-anchor" href="#💡-專家評析-283-字" aria-label="Permalink to &quot;💡 專家評析（283 字）&quot;">​</a></h2><ol><li><strong>費用僵固性壓力（利空）</strong>：營益率自 2022 年高點 15.0% 下滑至 2025 年 11.4%，連續 3 年萎縮，3 年累計下滑 -3.6pp。同期營收僅 2024 年增長，費用增幅顯著超額，揭示營運槓桿轉負——收入成長時利潤率反而壓縮，風險極高。</li><li><strong>營收動能停滯風險（利空）</strong>：2025 年營收微降 0.9% 已預示成長觸頂，2026 前 5 月年比 -15% 持續惡化。若半導體設備資本支出週期轉向保守，自有產品佔比 40% 的高營運槓桿結構將加速營益率下滑。</li><li><strong>以組合優化掩蓋核心競爭力衰退（風險）</strong>：毛利率靠自有產品佔比提升維穩，但代工本業僅 +4%，且海外銷貨（中國）2025 年衰退 -6.8%，顯示兩岸半導體測試代工競爭正在侵蝕市場份額。若設備訂單同步轉弱，以量補價的空間將全面消失。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (revenue_bridge 6261)</li><li>計算工具：財務分析工具.py (margin_analysis 6261)</li><li>原始數據：FinMind TaiwanStockMonthRevenue, FinMind TaiwanStockFinancialStatements</li><li>查詢參數：stock_id=6261, 年報 2024/2025 合併財報部門資訊（第 79 頁）</li><li>數據查詢日期：2026-05-11</li></ul>',19)])])}const g=e(l,[["render",o]]);export{c as __pageData,g as default};
